import React, { useMemo, useState } from "react";

/*
  Decisions.jsx
  ----------------------------------------------------
  Enterprise-grade Replacement Decisions / Approval page

  DATA CONTRACT (Backend ML APIs):
  --------------------------------
  ML Decision Engine should provide objects like:

  {
    systemId,
    owner,
    issueCategory,        // Hardware | Software | Security
    aiRecommendation,     // Replace | Repair | Reject
    confidence,           // 0–100
    estimatedCost,
    riskIfIgnored,        // Low | Medium | High
    status,               // Pending | Approved | Rejected
    snapshot: {
      ageYears,
      warrantyStatus,
      incidents,
      downtimeHours
    },
    evidence: {
      hardware,
      software,
      security
    },
    financials: {
      replacementCost,
      repairCost,
      downtimeCost,
      tco3yr
    },
    auditLog: []
  }
*/

// --------------------------------------------------
// Dummy Decision Queue (replace with backend API)
// --------------------------------------------------
const DECISIONS = [
  {
    systemId: "SYS-8472",
    owner: "Manufacturing / Line B",
    issueCategory: "Hardware",
    aiRecommendation: "Replace",
    confidence: 94,
    estimatedCost: 4200,
    riskIfIgnored: "High",
    status: "Pending",
    snapshot: {
      ageYears: 4,
      warrantyStatus: "Expired",
      incidents: 6,
      downtimeHours: 18,
    },
    evidence: {
      hardware: "Disk failure predicted within 18 days (contributes)",
      software: "Backup retries increase I/O stress (secondary)",
      security: "No malicious indicators (ruled out)",
    },
    financials: {
      replacementCost: 4200,
      repairCost: 1800,
      downtimeCost: 12000,
      tco3yr: "Replace saves ~$9,500 over 3 years",
    },
    auditLog: [
      "AI verdict generated with 94% confidence",
      "Hardware lifecycle exceeded expected threshold",
    ],
  },
  {
    systemId: "SYS-9031",
    owner: "Finance / Analytics",
    issueCategory: "Software",
    aiRecommendation: "Repair",
    confidence: 81,
    estimatedCost: 900,
    riskIfIgnored: "Medium",
    status: "Pending",
    snapshot: {
      ageYears: 2,
      warrantyStatus: "Active",
      incidents: 2,
      downtimeHours: 4,
    },
    evidence: {
      hardware: "No degradation detected (ruled out)",
      software: "Misconfigured service causing restarts (contributes)",
      security: "No threat activity (ruled out)",
    },
    financials: {
      replacementCost: 3500,
      repairCost: 900,
      downtimeCost: 2200,
      tco3yr: "Repair saves ~$2,600 over replacement",
    },
    auditLog: [
      "AI ruled out hardware failure",
      "Software configuration drift detected",
    ],
  },
];

// --------------------------------------------------
// Helpers
// --------------------------------------------------
const badge = (value) => {
  const map = {
    High: "bg-red-50 text-red-700",
    Medium: "bg-yellow-50 text-yellow-700",
    Low: "bg-green-50 text-green-700",
    Replace: "bg-red-50 text-red-700",
    Repair: "bg-blue-50 text-blue-700",
    Reject: "bg-slate-100 text-slate-700",
    Pending: "bg-yellow-50 text-yellow-700",
    Approved: "bg-green-50 text-green-700",
    Rejected: "bg-red-50 text-red-700",
  };
  return map[value] || "bg-slate-100 text-slate-700";
};

// --------------------------------------------------
// Component
// --------------------------------------------------
export default function Decisions() {
  const [selected, setSelected] = useState(null);

  // Header counters (executive summary)
  const summary = useMemo(() => {
    const pending = DECISIONS.filter(d => d.status === "Pending").length;
    const approved = DECISIONS.filter(d => d.status === "Approved").length;
    const rejected = DECISIONS.filter(d => d.status === "Rejected").length;
    const avgConfidence = Math.round(
      DECISIONS.reduce((a, b) => a + b.confidence, 0) / DECISIONS.length
    );
    return { pending, approved, rejected, avgConfidence };
  }, []);

  return (
    <div className="p-6 bg-gray-50 min-h-[calc(100vh-4rem)]">

      {/* ==================================================
          PAGE HEADER — DECISION SUMMARY
         ================================================== */}
      <div className="flex flex-col lg:flex-row lg:justify-between gap-6 mb-8">
        <div>
          <h1 className="text-2xl font-semibold text-slate-900">
            Replacement Decisions
          </h1>
          <p className="text-sm text-slate-600">
            AI-validated hardware replacement approvals
          </p>
        </div>

        <div className="grid grid-cols-2 sm:grid-cols-4 gap-3">
          <SummaryCard label="Pending Approvals" value={summary.pending} />
          <SummaryCard label="Approved Replacements" value={summary.approved} />
          <SummaryCard label="Rejected Claims" value={summary.rejected} />
          <SummaryCard label="Avg Confidence" value={`${summary.avgConfidence}%`} />
        </div>
      </div>

      {/* ==================================================
          DECISION QUEUE TABLE
         ================================================== */}
      <div className="bg-white rounded-lg shadow-sm overflow-x-auto">
        <table className="min-w-full divide-y">
          <thead className="bg-gray-50 text-xs uppercase text-gray-600">
            <tr>
              <th className="px-4 py-3 text-left">System</th>
              <th className="px-4 py-3 text-left">Owner</th>
              <th className="px-4 py-3 text-left">Issue</th>
              <th className="px-4 py-3 text-left">AI Recommendation</th>
              <th className="px-4 py-3 text-right">Confidence</th>
              <th className="px-4 py-3 text-right">Cost Impact</th>
              <th className="px-4 py-3 text-left">Risk</th>
              <th className="px-4 py-3 text-left">Status</th>
              <th className="px-4 py-3 text-left">Action</th>
            </tr>
          </thead>

          <tbody className="divide-y">
            {DECISIONS.map(d => (
              <tr key={d.systemId} className="hover:bg-gray-50">
                <td className="px-4 py-3 font-medium">{d.systemId}</td>
                <td className="px-4 py-3">{d.owner}</td>
                <td className="px-4 py-3">{d.issueCategory}</td>
                <td className="px-4 py-3">
                  <span className={`px-2 py-1 rounded-full text-xs ${badge(d.aiRecommendation)}`}>
                    {d.aiRecommendation}
                  </span>
                </td>
                <td className="px-4 py-3 text-right">{d.confidence}%</td>
                <td className="px-4 py-3 text-right">${d.estimatedCost}</td>
                <td className="px-4 py-3">
                  <span className={`px-2 py-1 rounded-full text-xs ${badge(d.riskIfIgnored)}`}>
                    {d.riskIfIgnored}
                  </span>
                </td>
                <td className="px-4 py-3">
                  <span className={`px-2 py-1 rounded-full text-xs ${badge(d.status)}`}>
                    {d.status}
                  </span>
                </td>
                <td className="px-4 py-3">
                  <button
                    onClick={() => setSelected(d)}
                    className="px-3 py-1.5 text-sm border rounded-md hover:bg-slate-50"
                  >
                    Review
                  </button>
                </td>
              </tr>
            ))}
          </tbody>
        </table>
      </div>

      {/* ==================================================
          DECISION REVIEW PANEL
         ================================================== */}
      {selected && (
        <div className="fixed inset-0 bg-black/30 z-50 flex">
          <div className="ml-auto w-full sm:w-[760px] bg-white shadow-xl overflow-y-auto">
            <div className="p-5 border-b flex justify-between">
              <div>
                <h2 className="text-lg font-semibold">
                  Decision Review — {selected.systemId}
                </h2>
                <p className="text-sm text-slate-500">
                  AI-backed replacement evaluation
                </p>
              </div>
              <button onClick={() => setSelected(null)} className="text-sm bg-slate-100 px-3 py-1 rounded-md">
                Close
              </button>
            </div>

            <div className="p-5 space-y-6">

              {/* System Snapshot */}
              <Section title="System Snapshot">
                <KeyValue label="Age" value={`${selected.snapshot.ageYears} years`} />
                <KeyValue label="Warranty" value={selected.snapshot.warrantyStatus} />
                <KeyValue label="Incidents" value={selected.snapshot.incidents} />
                <KeyValue label="Downtime" value={`${selected.snapshot.downtimeHours} hrs`} />
              </Section>

              {/* AI Verdict */}
              <Section title="AI Decision Verdict">
                <div className="flex items-center gap-3">
                  <span className={`px-3 py-1 rounded-full ${badge(selected.aiRecommendation)}`}>
                    {selected.aiRecommendation}
                  </span>
                  <span className="text-sm text-slate-600">
                    Confidence: <strong>{selected.confidence}%</strong>
                  </span>
                </div>
                <p className="text-sm text-slate-600 mt-2">
                  This recommendation is based on correlated system behavior and historical failure patterns,
                  validated against similar environments.
                </p>
              </Section>

              {/* Evidence */}
              <Section title="Cross-Pillar Evidence">
                <EvidenceCard title="Hardware" text={selected.evidence.hardware} />
                <EvidenceCard title="Software" text={selected.evidence.software} />
                <EvidenceCard title="Security" text={selected.evidence.security} />
              </Section>

              {/* Cost & ROI */}
              <Section title="Cost & ROI Analysis">
                <KeyValue label="Replacement Cost" value={`$${selected.financials.replacementCost}`} />
                <KeyValue label="Repair Cost" value={`$${selected.financials.repairCost}`} />
                <KeyValue label="Downtime Risk" value={`$${selected.financials.downtimeCost}`} />
                <KeyValue label="3-Year TCO" value={selected.financials.tco3yr} />
              </Section>

              {/* Actions */}
              <Section title="Final Decision">
                <div className="flex flex-wrap gap-3">
                  <ActionButton label="Approve Replacement" />
                  <ActionButton label="Approve Repair" />
                  <ActionButton label="Reject Claim" />
                  <ActionButton label="Request More Evidence" />
                </div>
              </Section>

              {/* Audit */}
              <Section title="Decision Audit Log">
                <ul className="text-sm text-slate-600 space-y-1">
                  {selected.auditLog.map((l, i) => (
                    <li key={i}>• {l}</li>
                  ))}
                </ul>
              </Section>

            </div>
          </div>
        </div>
      )}
    </div>
  );
}

/* --------------------------------------------------
   Small UI Components
-------------------------------------------------- */
const SummaryCard = ({ label, value }) => (
  <div className="bg-white border rounded-md px-4 py-2 text-sm">
    <div className="text-slate-500">{label}</div>
    <div className="font-semibold">{value}</div>
  </div>
);

const Section = ({ title, children }) => (
  <div>
    <h3 className="text-sm font-semibold text-slate-800 mb-2">{title}</h3>
    <div className="bg-gray-50 rounded-md p-4 space-y-2">
      {children}
    </div>
  </div>
);

const KeyValue = ({ label, value }) => (
  <div className="text-sm">
    <span className="text-slate-500">{label}:</span>{" "}
    <span className="font-medium">{value}</span>
  </div>
);

const EvidenceCard = ({ title, text }) => (
  <div className="bg-white border rounded-md p-3 text-sm">
    <div className="font-medium">{title}</div>
    <div className="text-slate-600 mt-1">{text}</div>
  </div>
);

const ActionButton = ({ label }) => (
  <button className="px-4 py-2 border rounded-md text-sm hover:bg-slate-50">
    {label}
  </button>
);
